mapper.select:
select u.*,f.original_name as sign_file_name from sys_user u
    left join sys_oss f on f.oss_id = u.sign_file_id
where u.user_id = #{userId}

select u.* from ( select u.user_id userId,u.user_name userName,u.login_name loginName,s.security_id securityId, s.security_name securityName,s.security_value securityValue,d.dept_id deptId ,d.dept_name deptName,group_concat(r.role_id) roleId,group_concat(r.role_name) roleName from sys_user u left join sys_security s on s.security_id = u.security_id LEFT JOIN sys_dept d on d.dept_id = u.dept_id left join sys_user_role sur on u.user_id = sur.user_id left join sys_role r on r.role_id = sur.role_id where u.status = '0' and u.del_flag = '0' group by u.user_id ) u where 1=1
and u.securityId = #{securityId}
and u.securityValue >= #{securityValue}
and u.deptId = #{deptId}
AND u.roleId like concat('%', #{roleId}, '%')
order by userName
